def build_report(chg_number: str) -> dict:
    """
    Build a report using the real pipeline steps 1-4, then inject
    the pre-written mock impact (step 5) to avoid LLM quota usage.
    Output structure is IDENTICAL to a live pipeline report.
    """
    print(f"\n  Building: {chg_number}")

    # Steps 1-4: real pipeline — no LLM
    change_data = fetch_change(chg_number)
    primary_ci  = change_data.get("primary_ci_id", "")

    if not primary_ci:
        print(f"  [SKIP] No primary CI for {chg_number}")
        return {}

    all_cis    = map_impacted_cis(primary_ci)
    classified = classify_environments(all_cis)
    graph      = build_impact_graph(all_cis)

    # Step 5: inject pre-written impact (no LLM call)
    impact = MOCK_IMPACTS.get(chg_number, {
        "severity": "MEDIUM",
        "estimated_downtime_minutes": 30,
        "rollback_complexity": "MEDIUM",
        "affected_business_services": [],
        "risk_summary": f"Pre-generated report for {chg_number}.",
        "potential_failures": [],
        "recommendations": [],
    })

    s = classified["summary"]
    print(f"  ✓ PROD={s['PROD']} DR={s['DR']} NonProd={s['NON-PROD']} "
          f"| Severity={impact['severity']}")

    return {
        "meta": {
            "chg_number":  chg_number,
            "analyzed_at": datetime.now().isoformat(),
            "elapsed_sec": 0,
            "source":      "test_run — mock historical data",
        },
        "change":     change_data,
        "ci_summary": classified["summary"],
        "ci_details": {
            "prod":    classified["prod"],
            "dr":      classified["dr"],
            "nonprod": classified["nonprod"],
            "unknown": classified["unknown"],
        },
        "graph":  graph,
        "impact": impact,
    }


def save_report(report: dict) -> str:
    os.makedirs("reports", exist_ok=True)
    chg  = report["meta"]["chg_number"]
    ts   = datetime.now().strftime("%Y%m%d_%H%M%S")
    path = f"reports/report_{chg}_{ts}.json"
    with open(path, "w") as f:
        json.dump(report, f, indent=2, default=str)
    print(f"  [saved] {path}")
    return path


