if __name__ == "__main__":
    print("\n" + "="*60)
    print("  FlowMaster — Generating historical reports from mock data")
    print("="*60)

    # Clear old reports so we don't accumulate stale data
    import shutil
    if os.path.exists("reports"):
        shutil.rmtree("reports")
        print("\n  [cleared] Old reports/ folder deleted")

    # Build and save all reports
    print("\nStep 1: Building reports (pipeline steps 1-4, no LLM)...")
    reports = []
    for chg in ALL_CHGS:
        report = build_report(chg)
        if report:
            save_report(report)
            reports.append(report)

    # Ingest into FAISS RAG
    print(f"\nStep 2: Ingesting {len(reports)} reports into FAISS RAG...")
    print("  (Requires GEMINI_API_KEY for embeddings)\n")
    rag_ok = False
    try:
        from rag.easy_rag import EasyRAG
        rag = EasyRAG()
        for r in reports:
            rag.ingest(r)
            print(f"  [indexed] {r['meta']['chg_number']}")
        stats  = rag.get_stats()
        rag_ok = True
        print(f"\n  RAG index: {stats.get('indexed_changes', len(reports))} vectors ready")
    except Exception as e:
        print(f"\n  [WARNING] RAG skipped: {e}")
        print("  Reports saved to disk — RAG will index on first app.py startup")

    rag_status = "READY" if rag_ok else "SKIPPED (run again with GEMINI_API_KEY set)"
